import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"秘法之球","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/4.B级/秘法之球.md","filePath":"4.资源分区/7.物品与装备/3.防具/4.B级/秘法之球.md"}'),o={name:"4.资源分区/7.物品与装备/3.防具/4.B级/秘法之球.md"};function b(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"秘法之球",tabindex:"-1"},[n("秘法之球 "),r("a",{class:"header-anchor",href:"#秘法之球","aria-label":'Permalink to "秘法之球"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="秘法之球-1" tabindex="-1">秘法之球 <a class="header-anchor" href="#秘法之球-1" aria-label="Permalink to &quot;秘法之球&quot;">​</a></h1><p>秘法之球</p><p>价格：B+2000<br> 类型：防具-轻盾<br> 伤害：5L<br> 体积：1<br> 格挡值：20<br> 伤害类型：物理-钝击</p><p>这是一个半径约5厘米，在异金属之上施加秘法铸造而成的金属球体，但是因为其使用的金属密度极大，重量非常夸张，可以视为3体积大小。<br> 秘法之球既是一位法师修行与战斗的必备品，也是法师本人身份与地位的象征。<br> 尊贵的客户可以在符合秘法之球大小要求的前提下自定义秘法之球的外观，它可以是太阳，苹果，骷髅头，甚至是一个印着科O大头照的篮球。</p><p>秘法之球的所有功能都必须在你注入能量后才可生效，若你未注入能量，则秘法之球只是一个3体积的金属球体，甚至连伤害和格挡值都不存在<br> 你需要在进入影片时选择一个你拥有的能量池，将其与秘法绑定，影片中不可更改。<br> 根据你注入的能量背后所代表的精神内核，秘法之球将会散发出不同的颜色的能量波动，下列是几种常见颜色<br> 红色————激情与叛逆<br> 蓝色————好奇与创新<br> 白色————秩序与团结<br> 绿色————生命与成长<br> 黑色————死亡与野心<br> 以上颜色与精神内核并不是绑定的，比如魔兽世界世界观中的邪能是绿色，你可以根据具体情况进行设置。<br> 散发出能量波动的秘法之球在视觉效果上会变得更大，根据你指定的能量的多寡，秘法之球将看起来半径增长5厘米~20厘米不等，能够将周围15米范围的光照等级提升一级。这只是一个视觉效果，不会真正增加秘法之球的体积。如果你感觉这太招摇，你也可以随时关闭能量波动。</p><p>作为高贵的法师，一直用手拿着沉重的铁球是有失体面的，即使这是昂贵的秘法之球。<br> 以一个反射动作，你消耗10点绑定能量以启动秘法之球，接着它的内在程序将自行运转，自主悬浮于你的触及范围内进行警戒巡视，这令你在当前场景内总是进行了基础规则中的常规格挡行为。在秘法之球进行格挡时，将会展开扇形外观的能量护盾，格挡防御也将转为能量防御。能量护盾的颜色将由持有者注入的能量决定，地位超然的持有者往往会在护盾上拥有更多装饰，比如家族纹章。你可以自定义自己的能量护盾样式。</p><p>因为秘法之球是依靠与持有者的魔力联系，以及其自主程序进行警戒巡视，所以除非其与持有者的联系被切断，否则秘法之球永远不会被击落；因为抵挡攻击的是法球而非持有者自身，因此持有者不受接触攻击影响。<br> 操控秘法之球依靠的并不是粗野的战士技巧，而是优雅的法术技艺。秘法之球进行的格挡将使用学识作为技能，并根据你注入的能量类型，心智类能量使用能量感知作为专业，非心智类能量使用能量爆发作为专业。<br> 你需要维持法球与你的能量联系才能保持秘法之球的运行，所以你使用秘法之球时仍将占用一个手部装备栏。</p><p>高级魔力炉心产出的能量除了用于法球自动巡视之外，还可以反馈给装备者自身。在你装备秘法之球时，每小时一次，你可以收集法球盈余的能量以补充自身魔力，进行一次关键属性检定，恢复成功数点能量，这计入你每日能量恢复上限。当然，法球只会产出你提前注入的能量池的能量。</p><p>在一些场合里，可能是为了体面，法师们并不希望自己身边飘着一个铁球，即使这是高贵的秘法之球。为了应对这种情况，秘法之球附带了一个100立方米的能量空间，你可以将任何非独立物品，包括秘法之球自身放入其中。不过如果你将秘法之球放入这个空间，那么你将因为不再装备法球，而失去自动格挡的功能，魔力炉心的能量产出也将暂停。放入或取出物品至少需要一个花招动作。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
